$kpi=$db->fetch("SELECT COUNT(*) total_order,COALESCE(SUM(order_qty),0) order_qty,COALESCE(SUM(completed_qty),0) completed_qty,COALESCE(SUM(scrap_qty),0) scrap_qty FROM production_order WHERE start_date BETWEEN ? AND ?",array($defaultFrom,$defaultTo));
?>
