pecialchars($p->plant_code,ENT_QUOTES,'UTF-8');?>"><?=htmlspecialchars($p->plant_code,ENT_QUOTES,'UTF-8');?></option><?php } ?></select></div><label class="control-label col-lg-1">Plant GR</label><div class="col-lg-2"><select id="filter_plant_id" class="form-control"><option value=""><?=prod_h('common_all', 'All');?></option><?php foreach($erpPlants as $p){ ?><option value="<?=intval($p->id);?>"><?=htmlspecialchars($p->plant_code.' - '.$p->plant_name,ENT_QUOTES,'UTF-8');?></option><?php } ?></select></div><div class="col-lg-2"><button id="btn_reset_prp" class="btn btn-default"><i class="fa fa-refresh"></i> <?=prod_h('common_reset', 'Reset');?></button> <button id="btn_excel_prp" class="btn btn-success"><i class="fa fa-file-excel-o"></i> <?=prod_h('common_excel', 'Excel');?></button></div></div><div class="form-group"><label class="control-label col-lg-2"><?=prod_h('common_search', 'Search');?></label><div class="col-lg-8"><input id="filter_keyword" class="form-control" placeholder="<?=prod_h('production_search_reports', 'Production order, material, SO, customer PO, BC doc');?>"></div></div></form></div></div>
