<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script>
<script>
var prpHeaders={order_summary:['No','PO','Status','Strategy','Plant','Material','Order Qty','Issued','Yield','GR Qty','Scrap','Yield %','Date'],material_consumption:['No','PO','Status','Start','Plant','Component','Required','Issued','Remaining','UOM','Issue Status'],output_gr:['No','GR No','Posting','PO','Confirmation','Material','Qty','UOM','Location','Stock Type','Status'],traceability:['No','GR No','Posting','PO','Output','Raw Material','Trace Qty','UOM','BC Document','Trace Source']};
function prpError(m){$('.isi_warning_delete').text(m||<?=prod_js('production_reports_process_failed', 'Production Reports failed to process.');?>);$('.error_data_delete').fadeIn();}
function prpFilters(){return{report_type:$('#report_type').val(),tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),status:$('#filter_status').val(),plant:$('#filter_plant').val(),plant_id:$('#filter_plant_id').val(),keyword:$('#filter_keyword').val()};}
function setHead(){var h=prpHeaders[$('#report_type').val()]||prpHeaders.order_summary;$('#prp_head').html(h.map(function(x){return '<th>'+x+'</th>';}).join(''));}
function prpShowDetail(row){var h=prpHeaders[$('#report_type').val()]||prpHeaders.order_summary,html='<div class="table-responsive"><table class="table table-bordered table-striped">';for(var i=0;i<h.length;i++){html+='<tr><th style="width:210px">'+h[i]+'</th><td>'+(row[i]||'-')+'</td></tr>';}html+='</table></div>';$('#prp_detail_body').html(html);$('#modal_prp_detail').modal('show');}
var dt;
$(function(){if($.fn.datepicker){$('.prp-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#report_type,#filter_status,#filter_plant,#filter_plant_id').select2({width:'100%',allowClear:true});}setHead();dt=$('#dtb_production_reports').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,destroy:true,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=prod_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],ajax:{url:'<?=base_admin();?>modul/production_reports/production_reports_data.php',type:'post',data:function(d){$.extend(d,prpFilters());},error:function(xhr){console.log(xhr.responseText);prpError(<?=prod_js('production_report_load_failed', 'Report data failed to load.');?>);}}});
function reload(){setHead();dt.destroy();$('#dtb_production_reports tbody').empty();dt=$('#dtb_production_reports').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=prod_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],ajax:{url:'<?=base_admin();?>modul/production_reports/production_reports_data.php',type:'post',data:function(d){$.extend(d,prpFilters());},error:function(xhr){console.log(xhr.responseText);prpError(<?=prod_js('production_report_load_failed', 'Report data failed to load.');?>);}}});}
$('#report_type').change(reload);$('#btn_filter_prp').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_prp').click(function(){$('#report_type').val('order_summary').trigger('change');$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_status,#filter_plant,#filter_plant_id').val('').trigger('change');$('#filter_keyword').val('');reload();});$('#btn_excel_prp,#btn_excel_prp_top').click(function(){window.location='<?=base_admin();?>modul/production_reports/production_reports_action.php?act=excel&'+$.param(prpFilters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
$('#dtb_production_reports tbody').on('click','tr',function(){var row=dt.row(this).data();if(row)prpShowDetail(row);});
});
</script>
